import AdminLayout from "../../AdminLayout";
import "./AddPatient.css";

export default function AddPatient() {
  return (
    <AdminLayout>
      <div className="patient-page">

        {/* Header */}
        <div className="patient-header">
          <h2>Patient Registration</h2>
          <div className="hl7">HL7 v2.5</div>
        </div>

        {/* Card */}
        <div className="card">

          {/* Patient Information */}
          <h3>Patient Information</h3>

          <div className="grid-top">
            <div className="full">
              <label>Medical Record Number (MRN)</label>
              <input placeholder="MRN123" />
            </div>

            <div className="photo">
              <div className="photo-box">
                <div className="avatar"></div>
                <button type="button">Upload Photo</button>
              </div>
            </div>

            <div>
              <label>First Name</label>
              <input placeholder="John" />
            </div>

            <div>
              <label>Last Name</label>
              <input placeholder="Doe" />
            </div>

            <div>
              <label>Display Name</label>
              <input placeholder="John Doe" />
            </div>

            <div>
              <label>Date of Birth</label>
              <input type="date" />
            </div>

            <div>
              <label>Gender</label>
              <select>
                <option>Male</option>
                <option>Female</option>
              </select>
            </div>

            <div>
              <label>Marital Status</label>
              <select>
                <option>Single</option>
                <option>Married</option>
              </select>
            </div>

            <div>
              <label>Age</label>
              <input placeholder="45" />
            </div>

            <div>
              <label>National ID Number</label>
              <input placeholder="784987012345678" />
            </div>
          </div>

          {/* Contact Details */}
          <h3>Contact Details</h3>

          <div className="grid">
            <div>
              <label>Address</label>
              <input placeholder="123 Main St" />
            </div>

            <div>
              <label>City</label>
              <select>
                <option>Dubai</option>
              </select>
            </div>

            <div>
              <label>Country</label>
              <select>
                <option>UAE</option>
              </select>
            </div>

            <div>
              <label>Mobile Number</label>
              <input placeholder="+971 050124567" />
            </div>
          </div>

          {/* Patient Identification */}
          <div className="section-head">
            <h3>Patient Identification</h3>
            <span>Attach or Scan ID</span>
          </div>

          <div className="grid">
            <div>
              <label>ID Type</label>
              <select>
                <option>Aadhar Card</option>
              </select>
            </div>

            <div>
              <label>ID Number</label>
              <input placeholder="1234 5678 9012" />
            </div>

            <div>
              <label>Expiry Date</label>
              <input type="date" />
            </div>
          </div>

          {/* Emergency Contact */}
          <h3>Emergency Contact</h3>

          <div className="grid">
            <div>
              <label>First Name</label>
              <input placeholder="Jane" />
            </div>

            <div>
              <label>Last Name</label>
              <input placeholder="Doe" />
            </div>

            <div>
              <label>Mobile Number</label>
              <input placeholder="+971 0509876543" />
            </div>
          </div>

          <div className="actions">
            <button className="primary">Register Patient</button>
          </div>

        </div>
      </div>
    </AdminLayout>
  );
